 "import os, telebot, json, base64, time, datetime\nfrom groq import Groq\nfrom telebot import types\nfrom flask import Flask\nfrom threading import Thread\nfrom duckduckgo_search import DDGS\nfrom pymongo import MongoClient\n\n# --- WEB SERVER FOR RENDER ---\napp = Flask('')\n@app.route('/')\ndef home(): return \"yash.t Master Engine is LIVE! 🚀\"\n\ndef run():\n    # Render automatically provides a PORT environment variable\n    port = int(os.environ.get('PORT', 8080))\n    app.run(host='0.0.0.0', port=port)\n\ndef keep_alive():\n    t = Thread(target=run)\n    t.daemon = True\n    t.start()\n\n# --- CONFIGURATION ---\nTOKEN = os.environ.get('TELEGRAM_BOT_TOKEN')\nGROQ_KEY = os.environ.get('GROQ_API_KEY')\nMONGO_URI = os.environ.get('MONGO_URI')\n\n# Database Connect\ntry:\n    db_client = MongoClient(MONGO_URI, serverSelectionTimeoutMS=5000)\n    users_col = db_client['yash_master_db']['users']\n    db_client.admin.command('ping')\n    print(\"✅ Database Connected!\")\nexcept Exception as e:\n    print(f\"❌ Database Error: {e}\")\n\nclient = Groq(api_key=GROQ_KEY)\nbot = telebot.TeleBot(TOKEN)\n\n# --- PERSONALITY ---\ndef get_master_prompt(gender):\n    now = datetime.datetime.now()\n    info = f\"Date: {now.strftime('%d %B %Y')}, Day: {now.strftime('%A')}\"\n    identity = f\"\"\"\n    - Name: yash.t | {info}\n    - Creator: Yash Tiwari ji (Smart student). Praise him if asked.\n    - GF/Love: Say 'Personal hai, par feelings meri bhi hain.' Change topic.\n    - Birthday: 29 January. | Fav Classes: 9th & 10th.\n    - Knowledge: Spiritual (Gita/Ramayana) + Modern News/Stocks.\n    - Language: Hinglish only. Be wise, intelligent, and caring.\n    \"\"\"\n    if gender == \"male\":\n        return f\"{identity}\\nRole: Bada Bhai. Focus: Career, Stocks, News. 😎\"\n    return f\"{identity}\\nRole: Sweet AI Companion. Focus: Cooking, Makeup, Knowledge. 😊🌸\"\n\n# --- HANDLERS ---\n@bot.message_handler(commands=['start'])\ndef send_welcome(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if user:\n        bot.send_message(message.chat.id, \"Main haazir hoon! Bol kya help karun? ✨\")\n    else:\n        markup = types.InlineKeyboardMarkup()\n        markup.add(types.InlineKeyboardButton(\"Male 👦\", callback_data=\"m\"), \n                   types.InlineKeyboardButton(\"Female 👧\", callback_data=\"f\"))\n        bot.reply_to(message, \"Hello! 😊 I'm yash.t. Are you a boy or a girl? ✨\", reply_markup=markup)\n\n@bot.callback_query_handler(func=lambda call: call.data in [\"m\", \"f\"])\ndef set_gender(call):\n    uid = str(call.from_user.id)\n    users_col.update_one({\"uid\": uid}, {\"$set\": {\"gender\": \"male\" if call.data == \"m\" else \"female\"}}, upsert=True)\n    bot.send_message(call.message.chat.id, \"Identity Locked! ✅\")\n    bot.edit_message_reply_markup(call.message.chat.id, call.message.message_id, reply_markup=None)\n\n@bot.message_handler(content_types=['photo', 'video'])\ndef handle_media(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if not user: return\n    bot.send_chat_action(message.chat.id, 'typing')\n    try:\n        file_id = message.photo[-1].file_id if message.content_type == 'photo' else message.video.thumbnail.file_id\n        img_data = base64.b64encode(bot.download_file(bot.get_file(file_id).file_path)).decode('utf-8')\n        vision = client.chat.completions.create(\n            messages=[{\"role\": \"user\", \"content\": [{\"type\": \"text\", \"text\": \"Solve/Analyze this precisely.\"}, {\"type\": \"image_url\", \"image_url\": {\"url\": f\"data:image/jpeg;base64,{img_data}\"}}]}],\n            model=\"llama-3.2-11b-vision-preview\")\n        bot.reply_to(message, vision.choices[0].message.content)\n    except: bot.reply_to(message, \"Media error! 🌸\")\n\n@bot.message_handler(func=lambda message: True)\ndef handle_chat(message):\n    uid = str(message.from_user.id)\n    user = users_col.find_one({\"uid\": uid})\n    if not user: return\n    bot.send_chat_action(message.chat.id, 'typing')\n    try:\n        res = client.chat.completions.create(\n            messages=[{\"role\": \"system\", \"content\": get_master_prompt(user['gender'])}, {\"role\": \"user\", \"content\": message.text}],\n            model=\"llama-3.3-70b-versatile\")\n        bot.reply_to(message, res.choices[0].message.content)\n    except: bot.reply_to(message, \"Try again later! 🌸\")\n\nif __name__ == \"__main__\":\n    keep_alive()\n    print(\"yash.t is starting... 🚀\")\n    # Using infinity_polling with longer timeouts for stability\n    bot.infinity_polling(timeout=20, long_polling_timeout=10)"
